# fix_crm_dark.ps1
Write-Host "Aplicando dark mode al CRM..." -ForegroundColor Cyan
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\crm\pages\CRMPage.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "Listo!" -ForegroundColor Green
